const cookie = $('Cookies holen').first().json.list?.[0]?.Cookie || '';
const events = ($('Aktive Events holen').first().json.list || [])
  .filter(e => e.EventLink && e.EventLink.trim() !== '');

const toInt = str => str ? parseInt(str.replace(/[^\d]/g, ''), 10) : 0;
const results = [];

for (const event of events) {
  const { Id, EventLink } = event;
  console.log(`Verarbeite Event ID ${Id}: ${EventLink}`);

  let html = '';
  try {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: EventLink,
      headers: {
        Cookie: cookie,
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
        Accept: 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8'
      },
      timeout: 20000
    });
    html = typeof resp === 'string' ? resp : JSON.stringify(resp);
  } catch(e) {
    console.log(`Fehler beim Abrufen von Event ${Id}: ${e.message}`);
    results.push({ json: { Id, status: 'fetch_error', error: e.message } });
    continue;
  }

  const angemeldetMatch  = html.match(/(\d+)\s*Personen angemeldet/)  || html.match(/>(\d+)<[^>]*>\s*Personen angemeldet/);
  const nichtBestMatch   = html.match(/(\d+)\s*noch nicht bestätigt/) || html.match(/(\d+)\s*nicht bestätigt/);
  const vorgemerktMatch  = html.match(/(\d+)\s*mal vorgemerkt/);
  const aufrufMatch      = html.match(/(\d+)\s*Aufrufe/);
  const maennerMatch     = html.match(/Männer[^(]*\((\d+)\)/)         || html.match(/M.nner[^(]*\((\d+)\)/);
  const frauenMatch      = html.match(/Frauen[^(]*\((\d+)\)/);
  const paareMatch       = html.match(/Paare[^(]*\((\d+)\)/);

  const stats = {
    Angemeldet:      angemeldetMatch ? toInt(angemeldetMatch[1]) : 0,
    NichtBestaetigt: nichtBestMatch  ? toInt(nichtBestMatch[1])  : 0,
    Vorgemerkt:      vorgemerktMatch ? toInt(vorgemerktMatch[1]) : 0,
    Aufrufe:         aufrufMatch     ? toInt(aufrufMatch[1])     : 0,
    Maenner:         maennerMatch    ? toInt(maennerMatch[1])    : 0,
    Frauen:          frauenMatch     ? toInt(frauenMatch[1])     : 0,
    Paare:           paareMatch      ? toInt(paareMatch[1])      : 0
  };
  console.log(`Event ${Id} Stats:`, JSON.stringify(stats));

  try {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: `http://f3-cookie-crawler:3000/api/events/${Id}`,
      headers: { 'Content-Type': 'application/json' },
      body: stats,
      json: true
    });
    results.push({ json: { Id, status: 'ok', ...stats } });
  } catch(e) {
    console.log(`Fehler beim Speichern von Event ${Id}: ${e.message}`);
    results.push({ json: { Id, status: 'patch_error', error: e.message } });
  }
}

// Dashboard Status Store schreiben
const statusEvents = results
  .filter(r => r.json.status === 'ok')
  .map(r => {
    const orig = events.find(e => e.Id === r.json.Id) || {};
    return {
      Id: r.json.Id,
      EventName:       orig.EventName  || '',
      EventDatum:      orig.EventDatum || '',
      EventLink:       orig.EventLink  || '',
      Status:          orig.Status     || 'aktiv',
      Wochentag:       orig.Wochentag  || '',
      Angemeldet:      r.json.Angemeldet      || 0,
      NichtBestaetigt: r.json.NichtBestaetigt || 0,
      Vorgemerkt:      r.json.Vorgemerkt      || 0,
      Aufrufe:         r.json.Aufrufe         || 0,
      Maenner:         r.json.Maenner         || 0,
      Frauen:          r.json.Frauen          || 0,
      Paare:           r.json.Paare           || 0
    };
  });

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://f3-cookie-crawler:3000/status',
    headers: { 'Content-Type': 'application/json' },
    body: { key: 'events', data: { events: statusEvents, updatedAt: new Date().toISOString() } },
    json: true
  });
  console.log('Dashboard Status Store: ' + statusEvents.length + ' Events geschrieben');
} catch(e) {
  console.log('Dashboard Status Store Fehler:', e.message);
}

return results;

